import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"唯心力量","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/唯心力量.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/唯心力量.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/唯心力量.md"};function l(p,a,_,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"唯心力量",tabindex:"-1"},[s("唯心力量 "),e("a",{class:"header-anchor",href:"#唯心力量","aria-label":'Permalink to "唯心力量"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="唯心力量-1" tabindex="-1">唯心力量 <a class="header-anchor" href="#唯心力量-1" aria-label="Permalink to &quot;唯心力量&quot;">​</a></h1><p>唯心力量<br> 价格：C+1500<br> 分类：被动<br> 描述：信念加持下短期爆发的产物，短期获得媲美斑纹的增幅，且没有折寿副作用。也有着燃烧心灵、斗气升腾、洗刷罪血、不辱xx之名及原作中未命名的多个种类称呼。说是“媲美斑纹”，其性能并不如斑纹全面，但却在单一方面有着更胜过斑纹的爆发力。<br> 效果：<br> 每影片一次，当你在战斗中（包括突袭轮）首次遭受致死伤害时，你将额外获得等同【决心/3】点临时生命，若在处理这些临时生命后你成功存活，则你在接下来的那一战斗场景内，以近战攻击主属性进行的检定获得等同于你平均生理属性等级*1点表现加值（若具有多个攻击主属性，则你需在购买时选择其中一项，而无法同时对多个攻击主属性生效）。<br> 在触发上述效果时，你可以再透支下轮的一个标准动作对其（即对你造成致死危机的单位）进行一次普通近战攻击，这会正常占用你的动作转化上限与对应AP（正常遵循透支规则），这次攻击具有【打断性】，若你使用的近战攻击主属性为【力量/敏捷】，则你需要额外消耗2点意志力，你进行的近战攻击将获得【破甲/高速8（对应力量/敏捷）】。</p><p>万难之门<br> 前置：唯心力量（逐级购买）<br> 价格：B+5000<br> 分类：被动<br> 描述：“我很清楚那些从鬼门关前走过一遭的生物都会变的更加强韧，为了规避可能到来的死亡，肉体会将那些日常生活中用不到的门全部打开，没有打开门的肉体会死亡，而将门打开的个体……”<br> 效果：<br> 你必须曾至少触发过一次唯心力量（见前置）的效果，才能购买万难之门这一能力，购买后你将失去唯心力量的效果，并以下述效果代替之：<br> 每影片一次，当你在战斗中（包括突袭轮）首次遭受致死伤害时，你将免疫那次伤害，这是一个B级祝福来源的无敌效果，触发该效果还会使你消耗9点意志力，若意志力不足则无法触发。</p><p>此后，在接下来的那一战斗场景内，你在生理属性相关检定上获得等同于你平均生理属性等级*1点表现加值，并获得等同平均生理属性等级/2点洞察防御；持续时间内，你的攻击附带【湮灭】，并在受到攻击时可以使那次攻击检定承受【劣化2】（基于洞察防御）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
